import type { DMMF } from '@prisma/dmmf'

/**
 * Maps Prisma scalar type names to their TypeScript equivalents suitable for
 * JSON-over-HTTP (REST) serialisation.
 *
 * `DateTime` becomes `string` because JSON has no native date type; callers
 * receive ISO 8601 strings from the server.
 * `Decimal` becomes `string` to avoid floating-point precision loss.
 * `Bytes` becomes `string` (base64-encoded payload).
 * `BigInt` becomes `string` for the same reason as Decimal.
 */
const SCALAR_TO_TS: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  BigInt: 'string',
  DateTime: 'string',
  Json: 'unknown',
  Bytes: 'string',
  Decimal: 'string',
}

/**
 * Returns the TypeScript type string for a DMMF field, taking into account
 * whether the field is a list and whether it is nullable.
 */
export function fieldToTsType(field: DMMF.Field, enumNames: ReadonlySet<string>): string {
  let base: string

  if (field.kind === 'scalar') {
    base = SCALAR_TO_TS[field.type] ?? 'unknown'
  } else if (field.kind === 'enum') {
    base = field.type
  } else {
    // Relation fields (kind === 'object') are included as optional nested
    // objects so that callers can inspect eager-loaded data when the server
    // sends it; they are always typed as unknown arrays or objects because the
    // exact shape depends on server-side include/select options.
    base = enumNames.has(field.type) ? field.type : 'unknown'
  }

  if (field.isList) {
    base = `${base}[]`
  }

  if (!field.isRequired && !field.isList) {
    base = `${base} | null`
  }

  return base
}

/**
 * Returns `true` for fields that should appear in the generated TypeScript
 * model interface (scalar + enum fields; relation fields are excluded from the
 * primary interface shape but are handled separately in the client method
 * return types).
 */
export function isInterfaceField(field: DMMF.Field): boolean {
  return field.kind === 'scalar' || field.kind === 'enum'
}

/**
 * Returns `true` for fields that a caller must supply when creating a record —
 * i.e. required scalar/enum fields that have no server-side default and are
 * not auto-generated.
 */
export function isRequiredCreateField(field: DMMF.Field): boolean {
  return (
    isInterfaceField(field) &&
    field.isRequired &&
    !field.hasDefaultValue &&
    !field.isGenerated &&
    !field.isUpdatedAt
  )
}

