import type { DMMF } from '@prisma/dmmf'

import { fieldToTsType, isInterfaceField, isRequiredCreateField } from './type-mapper'

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

/** Converts `UserProfile` → `userProfile` (lowercase first letter). */
function lcFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/** Indents every line of `text` by `spaces` spaces. */
function indent(text: string, spaces: number): string {
  const pad = ' '.repeat(spaces)
  return text
    .split('\n')
    .map((line) => (line.length > 0 ? pad + line : line))
    .join('\n')
}

// ---------------------------------------------------------------------------
// Section generators
// ---------------------------------------------------------------------------

/** Emits a TypeScript union-type alias for each Prisma enum. */
function generateEnumTypes(enums: readonly DMMF.DatamodelEnum[]): string {
  if (enums.length === 0) return ''

  const lines: string[] = ['// ------------------------------------------------------------------', '// Enums', '// ------------------------------------------------------------------', '']

  for (const e of enums) {
    if (e.documentation) {
      lines.push(`/** ${e.documentation} */`)
    }
    const values = e.values.map((v) => JSON.stringify(v.name)).join(' | ')
    lines.push(`export type ${e.name} = ${values}`)
    lines.push('')
  }

  return lines.join('\n')
}

/** Emits the model interface — scalar and enum fields only. */
function generateModelInterface(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const lines: string[] = []

  if (model.documentation) {
    lines.push(`/** ${model.documentation} */`)
  }

  lines.push(`export interface ${model.name} {`)

  for (const field of model.fields) {
    if (!isInterfaceField(field)) continue
    const tsType = fieldToTsType(field, enumNames)
    if (field.documentation) {
      lines.push(`  /** ${field.documentation} */`)
    }
    lines.push(`  ${field.name}: ${tsType}`)
  }

  // Relation fields appear as optional unknowns so that callers can access
  // eagerly-loaded data without type errors while keeping the base interface
  // database-provider-agnostic.
  for (const field of model.fields) {
    if (field.kind !== 'object') continue
    const tsType = field.isList ? `${field.type}[]` : `${field.type} | null`
    lines.push(`  ${field.name}?: ${tsType}`)
  }

  lines.push('}')

  return lines.join('\n')
}

/** Emits `ModelCreateInput` — required fields are non-optional; optional and
 *  defaulted fields carry `?`. Relation fields are excluded. */
function generateCreateInput(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const lines: string[] = [`export interface ${model.name}CreateInput {`]

  for (const field of model.fields) {
    if (!isInterfaceField(field)) continue
    const tsType = fieldToTsType(field, enumNames)
    const optional = isRequiredCreateField(field) ? '' : '?'
    lines.push(`  ${field.name}${optional}: ${tsType}`)
  }

  lines.push('}')
  return lines.join('\n')
}

/** Emits `ModelUpdateInput` — all fields optional. */
function generateUpdateInput(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const lines: string[] = [`export interface ${model.name}UpdateInput {`]

  for (const field of model.fields) {
    if (!isInterfaceField(field)) continue
    const tsType = fieldToTsType(field, enumNames)
    lines.push(`  ${field.name}?: ${tsType}`)
  }

  lines.push('}')
  return lines.join('\n')
}

/** Emits `ModelWhereUniqueInput` containing only `@id` and `@unique` fields. */
function generateWhereUniqueInput(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const lines: string[] = [`export interface ${model.name}WhereUniqueInput {`]

  for (const field of model.fields) {
    if (!isInterfaceField(field)) continue
    if (!field.isId && !field.isUnique) continue
    const base = fieldToTsType(field, enumNames).replace(' | null', '')
    lines.push(`  ${field.name}?: ${base}`)
  }

  lines.push('}')
  return lines.join('\n')
}

/**
 * Emits the internal `ModelRestClient` class with the five CRUD methods.
 *
 * REST conventions used:
 *   GET    /modelName            → findMany  (query: skip, take)
 *   GET    /modelName/unique     → findUnique (query: where=<JSON>; 404 → null)
 *   POST   /modelName            → create    (body: CreateInput)
 *   PATCH  /modelName            → update    (body: { where, data })
 *   DELETE /modelName            → delete    (body: { where })
 */
function generateModelClient(model: DMMF.Model): string {
  const resourcePath = lcFirst(model.name)
  const cls = `${model.name}RestClient`

  const findMany = [
    `async findMany(params?: FindManyParams): Promise<${model.name}[]> {`,
    `  const url = new URL(\`\${this.#config.baseUrl}/${resourcePath}\`)`,
    `  if (params?.skip !== undefined) url.searchParams.set('skip', String(params.skip))`,
    `  if (params?.take !== undefined) url.searchParams.set('take', String(params.take))`,
    `  const response = await fetch(url.toString(), {`,
    `    method: 'GET',`,
    `    headers: { 'Content-Type': 'application/json', ...this.#config.headers },`,
    `  })`,
    `  if (!response.ok) {`,
    `    throw new RestClientError('GET', '/${resourcePath}', response.status, response.statusText)`,
    `  }`,
    `  return response.json() as Promise<${model.name}[]>`,
    `}`,
  ].join('\n')

  const findUnique = [
    `async findUnique(where: ${model.name}WhereUniqueInput): Promise<${model.name} | null> {`,
    `  const url = new URL(\`\${this.#config.baseUrl}/${resourcePath}/unique\`)`,
    `  url.searchParams.set('where', JSON.stringify(where))`,
    `  const response = await fetch(url.toString(), {`,
    `    method: 'GET',`,
