/** Converts `UserProfile` → `userProfile` (lowercase first letter). */
function lcFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/** Indents every line of `text` by `spaces` spaces. */
function indent(text: string, spaces: number): string {
  const pad = ' '.repeat(spaces)
  return text
    .split('\n')
    .map((line) => (line.length > 0 ? pad + line : line))
    .join('\n')
}

// ---------------------------------------------------------------------------
// Section generators
// ---------------------------------------------------------------------------

/** Emits a TypeScript union-type alias for each Prisma enum. */
function generateEnumTypes(enums: readonly DMMF.DatamodelEnum[]): string {
  if (enums.length === 0) return ''

  const lines: string[] = ['// ------------------------------------------------------------------', '// Enums', '// ------------------------------------------------------------------', '']

  for (const e of enums) {
    if (e.documentation) {
      lines.push(`/** ${e.documentation} */`)
    }
    const values = e.values.map((v) => JSON.stringify(v.name)).join(' | ')
    lines.push(`export type ${e.name} = ${values}`)
    lines.push('')
  }

  return lines.join('\n')
}

/** Emits the model interface — scalar and enum fields only. */
function generateModelInterface(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const lines: string[] = []

  if (model.documentation) {
    lines.push(`/** ${model.documentation} */`)
  }

  lines.push(`export interface ${model.name} {`)

  for (const field of model.fields) {
    if (!isInterfaceField(field)) continue
    const tsType = fieldToTsType(field, enumNames)
    if (field.documentation) {
      lines.push(`  /** ${field.documentation} */`)
    }
    lines.push(`  ${field.name}: ${tsType}`)
  }

  // Relation fields appear as optional unknowns so that callers can access
  // eagerly-loaded data without type errors while keeping the base interface
  // database-provider-agnostic.
  for (const field of model.fields) {
    if (field.kind !== 'object') continue
    const tsType = field.isList ? `${field.type}[]` : `${field.type} | null`
    lines.push(`  ${field.name}?: ${tsType}`)
  }

  lines.push('}')

  return lines.join('\n')
}

