 *  defaulted fields carry `?`. Relation fields are excluded. */
function generateCreateInput(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const lines: string[] = [`export interface ${model.name}CreateInput {`]

  for (const field of model.fields) {
    if (!isInterfaceField(field)) continue
    const tsType = fieldToTsType(field, enumNames)
    const optional = isRequiredCreateField(field) ? '' : '?'
    lines.push(`  ${field.name}${optional}: ${tsType}`)
  }

  lines.push('}')
  return lines.join('\n')
}

