function generateUpdateInput(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const lines: string[] = [`export interface ${model.name}UpdateInput {`]

  for (const field of model.fields) {
    if (!isInterfaceField(field)) continue
    const tsType = fieldToTsType(field, enumNames)
    lines.push(`  ${field.name}?: ${tsType}`)
  }

  lines.push('}')
  return lines.join('\n')
}

