function generateWhereUniqueInput(model: DMMF.Model, enumNames: ReadonlySet<string>): string {
  const lines: string[] = [`export interface ${model.name}WhereUniqueInput {`]

  for (const field of model.fields) {
    if (!isInterfaceField(field)) continue
    if (!field.isId && !field.isUnique) continue
