import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import { generatorHandler } from '@prisma/generator-helper'

import { generateRestClient } from './generate-rest-client'

const GENERATOR_NAME = 'prisma-client-rest'
const PRETTY_NAME = 'Prisma REST Client'
const DEFAULT_OUTPUT = './generated/prisma-rest-client'
const OUTPUT_FILENAME = 'index.ts'

/**
 * Returns the resolved output directory for the generator.
 *
 * The output path is taken from the generator config (set by the user in
 * `schema.prisma` / `prisma.config.ts`). When the user has not provided an
 * explicit path, the Prisma CLI substitutes the manifest's `defaultOutput`.
 */
function resolveOutputDir(config: GeneratorConfig): string {
  if (!config.output?.value) {
    throw new Error(`${PRETTY_NAME}: output path is required. Add \`output = "<path>"\` to the generator block.`)
  }
  return config.output.value
}

export function registerGenerator(): void {
  generatorHandler({
    onManifest(_config: GeneratorConfig): GeneratorManifest {
      return {
        prettyName: PRETTY_NAME,
        defaultOutput: DEFAULT_OUTPUT,
      }
    },

    async onGenerate(options: GeneratorOptions): Promise<void> {
      const outputDir = resolveOutputDir(options.generator)

      await fs.mkdir(outputDir, { recursive: true })

      const clientSource = generateRestClient(options.dmmf)
      const outputPath = path.join(outputDir, OUTPUT_FILENAME)

      await fs.writeFile(outputPath, clientSource, 'utf-8')

      console.log(`${PRETTY_NAME}: written to ${outputPath}`)
    },
  })
}

